#include "flow_yfs201.h"
#include <Arduino.h>
#define FLOW_PIN 25
static volatile uint16_t _pulses=0;
static float _lpm=0,_totalL=0;static unsigned long _l=0;
void IRAM_ATTR _flow_isr(){_pulses++;}
void flow_setup(){pinMode(FLOW_PIN,INPUT_PULLUP);attachInterrupt(FLOW_PIN,_flow_isr,RISING);Serial.println("[flow] OK");}
void flow_loop(){if(millis()-_l<1000)return;unsigned long dt=millis()-_l;_l=millis();_lpm=_pulses*60.0/7.5;_totalL+=_pulses/7.5/60.0;_pulses=0;}
float flow_get_liters_per_min(){return _lpm;}
float flow_get_total_liters(){return _totalL;}
void flow_reset_total(){_totalL=0;}
